set mon = '02';
set start_dt = '20230101';
set end_dt = to_char(last_day(dateadd(month, -1, current_date)), 'yyyymmdd');

show variables;

select current_date








select distinct
    floor(clmbl.incur_dt_id / 10000) as incur_year
  , floor(clmbl.incur_dt_id / 100)   as incur_month
  , ben.ben_lvl
  , cpt.cpt_cd
  , cpt.proc_desc
  , case
        when cpt.cpt_cd in ('98940', '98941', '98942') then 'Chiro'
        when plsrv.plsrv_cd in ('11', '49')           then 'Office'
        when plsrv.plsrv_cd in ('22', '62', '19', '24') then 'OP_REHAB'
        else 'Other'
    end as category
  , case
        when clmbl.d_lgl_enty_sk <> 3
             and bst.st_cd = 'NY'
             and bst.src_area_id = 99 then 'NY'
        when bst.st_cd = 'FL'
             and bst.src_area_id = 99 then 'FL'
        when bst.st_cd = 'MA' then 'MA'
        when clmbl.d_lgl_enty_sk = 3 then bst.st_cd
        else geo.d_st_cd
    end as state
  , plsrv.plsrv_cd as placeofservice_code
  , plsrv.plsrv_desc as placeofservice_desc
  , case
        when floor(clmbl.incur_dt_id / 10000) = 2023
             and to_char(
                   to_date(cast(clmbl.clm_pd_dt_id as string), 'yyyymmdd')
                 , 'yyyymm'
               ) <= '2024' || $mon then 1
        when floor(clmbl.incur_dt_id / 10000) = 2024
             and to_char(
                   to_date(cast(clmbl.clm_pd_dt_id as string), 'yyyymmdd')
                 , 'yyyymm'
               ) <= '2025' || $mon then 1
        when floor(clmbl.incur_dt_id / 10000) = 2025
             and to_char(
                   to_date(cast(clmbl.clm_pd_dt_id as string), 'yyyymmdd')
                 , 'yyyymm'
               ) <= '2026' || $mon then 1
        else 0
    end as pt_y2
  , sum(clmbl.adj_ben_amt)          as claims
  , count(clmbl.clm_nbr)            as bl_cnt
  , count(distinct clmbl.clm_nbr)   as claim_cnt
from ublia_prd_isdc_prd_db.bdr_dm.f_clm_bil_ln_hist as clmbl
join ublia_prd_isdc_prd_db.bdr_conf.d_pln_ben_mod as pln
	on clmbl.d_pln_ben_mod_sk = pln.d_pln_ben_mod_sk
join ublia_prd_isdc_prd_db.bdr_conf.d_ben as ben
  on clmbl.d_ben_sk = ben.d_ben_sk
join ublia_prd_isdc_prd_db.bdr_dm.d_cpt_look          as cpt
  on clmbl.d_cpt_look_sk = cpt.d_cpt_look_sk
join ublia_prd_isdc_prd_db.bdr_conf.d_geo_xref        as geo
  on clmbl.res_d_geo_xref_sk = geo.d_geo_xref_sk
join ublia_prd_isdc_prd_db.bdr_conf.d_calc_rt         as bst
  on clmbl.d_calc_rt_sk = bst.d_calc_rt_sk
left join ublia_prd_isdc_prd_db.bdr_dm.f_clm_hist     as clm
  on clmbl.f_clm_hist_sk = clm.f_clm_hist_sk
left join ublia_prd_isdc_prd_db.bdr_dm.d_plsrv        as plsrv
  on clm.d_plsrv_sk = plsrv.d_plsrv_sk
where clmbl.incur_dt_id between $start_dt and 20251231
  and clmbl.clm_pd_dt_id between $start_dt and $end_dt
  and pln.prdct_grp = 'Med Supp'
  and cpt.cpt_cd in (
        '92507','92508','92526','97012','97016','97018','97022','97024','97026','97028'
      , '97032','97033','97034','97035','97036','97039','97110','97112','97113','97116'
      , '97124','97139','97140','97150','97164','97168','97530','97533','97535','97537'
      , '97542','97545','97546','97750','97755','97760','97761','97799','g0283'
      , '98940','98941','98942'
    )
group by
    incur_year
  , incur_month
  , ben.ben_lvl
  , cpt.cpt_cd
  , cpt.proc_desc
  , category
  , state
  , plsrv.plsrv_cd
  , plsrv.plsrv_desc
  , pt_y2
order by
    incur_year
  , incur_month
  , ben.ben_lvl
  , cpt.cpt_cd
  , cpt.proc_desc
  , category
  , plsrv.plsrv_cd
  , plsrv.plsrv_desc;

use role 


select * from UBLIA_PRD_ISDC_PRD_DB.BDR_CONF.d_prov


select * from 


BDR_CONFfc                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      